SELECT t.tplan_no AS tplanNo, t.member_no AS memberNo, t.tplan_title AS tplanTitle, t.tplan_desc AS tplanDesc, t.tplan_region AS tplanRegion, t.tplan_like AS tplanLike,
/* ?’Ў мІ?лІҲм§ё ?? мІ?лІҲм§ё ?ңм„ң ?қлӢ№??к°Җ??мІ?лІҲм§ё л©”лүҙ ?ҙл?м§ҖлҘ?к°Җ?ёмҳӨ???ңлёҢмҝјлҰ¬ */ ( SELECT m.MENU_IMG FROM travel_schedule_tbl s JOIN menu_tbl m ON s.rest_no = m.REST_NO WHERE s.tplan_no = t.tplan_no AND s.tsche_day_no = 1 AND s.tsche_order_no = 1 ORDER BY m.MENU_NO ASC LIMIT 1 ) AS menuImg
FROM travel_plan_tbl t WHERE t.tplan_status = 1 ORDER BY t.tplan_like DESC, t.created_at DESC LIMIT 6
